1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	};
8	
9	export function runScenario(scenario: unknown): { results: unknown[] } {
10	  const steps = (scenario as { steps: { items: { type: string }[] }[] }).steps;
11	  const items = steps[0].items;
12	  let premium = PROCESSING_FEE;
13	  if (items.length > 0) {
14	    const base = items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
15	    premium = base + base * FIRST_INSURANCE_RATE + PROCESSING_FEE;
16	  }
17	  return { results: [{ premium }] };
18	}
